drop database if exists ApiDragonBall;

create database if not exists ApiDragonBall;

use ApiDragonBall;

create table SagaBall(

    id int NOT NULL AUTO_INCREMENT,

    nombre varchar (1024),

    genre varchar (1024),

    race varchar(1024),

    imagen varchar(1024),

    planet varchar(1024),

    descripcion varchar (1024),

    biography varchar(1024),

    PRIMARY KEY (id)

);

create table SagaBallZ(

    id int NOT NULL AUTO_INCREMENT,

    nombre varchar(1024),

    genre varchar(1024),

    race varchar(1024),

    imagen varchar(1024),

    planet varchar(1024),
    
    descripcion varchar(1024),

    biography varchar(1024),

    transformations varchar(1024),

    PRIMARY KEY (id)

);

create table Dragon(

    id int NOT NULL AUTO_INCREMENT,
    
    nombre varchar(1024),

    imagen varchar(1024),

    descripcion varchar(1024),

    biography varchar(1024),

    PRIMARY KEY (id)

);


